def hashcode(n: int) -> str:
    return hashlib.sha256(str(n).encode('utf-8')).hexdigest()

@pytest.mark.parametrize("products, productPrices, productSold, soldPrice, result, testcase", q8_testcases)
def test_q8(products, productPrices, productSold, soldPrice, result, testcase):
    if testcase == True:
        assert priceCheck(products, productPrices, productSold, soldPrice) == result
    else:
        assert hashcode(priceCheck(products, productPrices, productSold, soldPrice)) == result